-- RH 004 — Sous-processus RH multi-personnes → affectation GROUPE (team),
-- toute l'équipe du service voit la tâche (modèle boîte partagée du flux).
-- Réglementaire (221606) reste en personne (Florence, fixed_user — cf. rh_003).
UPDATE sub_process_templates SET assignment_type='team', target_group_id = v.gid::uuid, target_assignee_id = NULL
FROM (VALUES
  ('22222222-2222-4222-8222-222222221601','33333333-3333-4333-8333-000000000001'), -- Onboarding IT
  ('22222222-2222-4222-8222-222222221602','33333333-3333-4333-8333-000000000003'), -- Onboarding RH
  ('22222222-2222-4222-8222-222222221603','33333333-3333-4333-8333-000000000004'), -- Onboarding SG
  ('22222222-2222-4222-8222-222222221604','33333333-3333-4333-8333-000000000005'), -- Onboarding Comm
  ('22222222-2222-4222-8222-222222221605','33333333-3333-4333-8333-000000000002'), -- Onboarding Digital applis
  ('22222222-2222-4222-8222-222222221607','33333333-3333-4333-8333-000000000006'), -- Onboarding Compta
  ('22222222-2222-4222-8222-222222221611','33333333-3333-4333-8333-000000000003'), -- Offboarding RH
  ('22222222-2222-4222-8222-222222221612','33333333-3333-4333-8333-000000000001'), -- Offboarding IT
  ('22222222-2222-4222-8222-222222221613','33333333-3333-4333-8333-000000000004'), -- Offboarding SG
  ('22222222-2222-4222-8222-222222221614','33333333-3333-4333-8333-000000000002'), -- Offboarding Digital applis
  ('22222222-2222-4222-8222-222222221615','33333333-3333-4333-8333-000000000006'), -- Offboarding Compta
  ('22222222-2222-4222-8222-222222221621','33333333-3333-4333-8333-000000000003'), -- Mutation RH
  ('22222222-2222-4222-8222-222222221622','33333333-3333-4333-8333-000000000001'), -- Mutation IT
  ('22222222-2222-4222-8222-222222221623','33333333-3333-4333-8333-000000000006'), -- Mutation Compta
  ('22222222-2222-4222-8222-222222221624','33333333-3333-4333-8333-000000000004'), -- Mutation SG
  ('22222222-2222-4222-8222-222222221631','33333333-3333-4333-8333-000000000003'), -- Promotion RH
  ('22222222-2222-4222-8222-222222221632','33333333-3333-4333-8333-000000000001')  -- Promotion IT
) AS v(sp_id, gid)
WHERE sub_process_templates.id = v.sp_id::uuid;
